import random
import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.is_moving = False
        self.direction = None

    def call_lift(self, floor):
        self.passengers.append(floor)
        if not self.is_moving:
            self.start_moving()

    def start_moving(self):
        self.is_moving = True
        self.direction = 'up' if self.passengers[0] > self.current_floor else 'down'

    def move(self):
        if self.direction == 'up':
            self.current_floor += 1
        else:
            self.current_floor -= 1

        if self.current_floor == self.passengers[0]:
            self.passengers.pop(0)
            if not self.passengers:
                self.is_moving = False
                self.direction = None
            else:
                self.direction = 'up' if self.passengers[0] > self.current_floor else 'down'

    def run(self):
        while True:
            if self.is_moving:
                self.move()
            else:
                if self.passengers:
                    self.start_moving()
            time.sleep(0.5)

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.crowd_size = 0

    def simulate_day(self, crowd_size):
        self.crowd_size = crowd_size
        for _ in range(24 * 60):
            self.simulate_hour()
            time.sleep(0.1)

    def simulate_hour(self):
        for _ in range(60):
            self.simulate_minute()

    def simulate_minute(self):
        for _ in range(self.crowd_size):
            self.call_lift()
        for lift in self.lifts:
            lift.run()

    def call_lift(self):
        lift = random.choice(self.lifts)
        lift.call_lift(random.randint(0, self.num_floors - 1))

