import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.direction = "up"
        self.last_stop_time = time.time()

    def move(self):
        if self.direction == "up":
            self.current_floor = min(self.current_floor + 1, self.num_floors)
        else:
            self.current_floor = max(self.current_floor - 1, 0)

        self.last_stop_time = time.time()

        for passenger in self.passengers[:]:
            if passenger.destination == self.current_floor:
                self.passengers.remove(passenger)

        if self.current_floor == 0 or self.current_floor == self.num_floors:
            self.direction = "up" if self.direction == "down" else "down"

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

class Passenger:
    def __init__(self, start_floor, end_floor):
        self.start_floor = start_floor
        self.destination = end_floor

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passengers = []

    def simulate_day(self, num_passengers):
        for _ in range(num_passengers):
            start_floor = random.randint(0, self.num_floors - 1)
            end_floor = random.randint(0, self.num_floors - 1)
            while end_floor == start_floor:
                end_floor = random.randint(0, self.num_floors - 1)
            passenger = Passenger(start_floor, end_floor)
            self.passengers.append(passenger)
            self.assign_passenger(passenger)

        for _ in range(self.num_floors * 10):
            for lift in self.lifts:
                lift.move()
            time.sleep(0.1)

    def assign_passenger(self, passenger):
        min_distance = float("inf")
        closest_lift = None
        for lift in self.lifts:
            distance = abs(lift.current_floor - passenger.start_floor)
            if distance < min_distance:
                min_distance = distance
                closest_lift = lift
        closest_lift.add_passenger(passenger)

