import random
import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.is_moving = False
        self.direction = 0

    def call_lift(self, floor):
        self.passengers.append(floor)
        self.passengers = sorted(self.passengers)
        if not self.is_moving:
            self.move()

    def move(self):
        self.is_moving = True
        while self.passengers:
            current_floor = self.passengers[0]
            if current_floor > self.current_floor:
                self.direction = 1
            else:
                self.direction = -1
            while self.current_floor != current_floor:
                self.current_floor += self.direction
                time.sleep(0.5)
                print(f"Lift is on floor {self.current_floor}")
            self.passengers.pop(0)
            print(f"Lift stopped at floor {self.current_floor} and picked up/dropped off passengers")
        self.is_moving = False

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]

    def simulate_day(self, num_people):
        for _ in range(num_people):
            start_floor = random.randint(0, self.num_floors - 1)
            end_floor = random.randint(0, self.num_floors - 1)
            while start_floor == end_floor:
                end_floor = random.randint(0, self.num_floors - 1)
            lift = min(self.lifts, key=lambda l: abs(l.current_floor - start_floor))
            lift.call_lift(end_floor)

        for hour in range(24):
            print(f"Hour {hour}:")
            if hour < 9 or hour >= 17:
                num_people = random.randint(10, 50)
            else:
                num_people = random.randint(1, 10)
            self.simulate_day(num_people)
            time.sleep(1)

