import random
import time

class Lift:
    def __init__(self, num_floors):
        self.num_floors = num_floors
        self.current_floor = 0
        self.waiting_passengers = []
        self.passengers_inside = []

    def call_lift(self, floor):
        self.waiting_passengers.append(floor)

    def enter_lift(self, passenger):
        self.passengers_inside.append(passenger)

    def exit_lift(self, passenger):
        self.passengers_inside.remove(passenger)

    def move_lift(self):
        if self.waiting_passengers:
            target_floor = min(self.waiting_passengers)
            self.waiting_passengers.remove(target_floor)
            print(f"Lift moving from floor {self.current_floor} to floor {target_floor}")
            self.current_floor = target_floor
            for passenger in self.passengers_inside[:]:
                if passenger == self.current_floor:
                    self.exit_lift(passenger)
                    print(f"Passenger exiting at floor {passenger}")
        else:
            self.current_floor = (self.current_floor + 1) % self.num_floors
            print(f"Lift moving from floor {self.current_floor} to floor {(self.current_floor + 1) % self.num_floors}")

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passengers = []

    def add_passenger(self, floor, target_floor):
        self.passengers.append((floor, target_floor))

    def run_simulation(self, simulation_time):
        for _ in range(simulation_time):
            for _ in range(random.randint(0, 10)):
                floor = random.randint(0, self.num_floors - 1)
                target_floor = random.randint(0, self.num_floors - 1)
                self.add_passenger(floor, target_floor)

            for lift in self.lifts:
                lift.move_lift()

            for passenger in self.passengers[:]:
                floor, target_floor = passenger
                if floor == lift.current_floor:
                    lift.enter_lift(target_floor)
                    self.passengers.remove(passenger)
                    print(f"Passenger entering lift at floor {floor}")

            time.sleep(1)

