class Passenger:
    def __init__(self, start_floor, end_floor):
        self.start_floor = start_floor
        self.end_floor = end_floor

class OfficeBuilding:
    def __init__(self, num_lifts, num_floors):
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.num_floors = num_floors
        self.passengers = []

    def simulate_day(self, num_passengers):
        for _ in range(num_passengers):
            start_floor = random.randint(0, self.num_floors - 1)
            end_floor = random.randint(0, self.num_floors - 1)
            while start_floor == end_floor:
                end_floor = random.randint(0, self.num_floors - 1)
            passenger = Passenger(start_floor, end_floor)
            self.passengers.append(passenger)

        for hour in range(24):
            print(f"Hour {hour}")
            self.handle_passengers(hour)
            self.move_lifts()
            time.sleep(1)

    def handle_passengers(self, hour):
        if hour in [8, 9, 17, 18]:
            # Morning and evening rush hours
            for passenger in self.passengers:
                if passenger.start_floor == 0 or passenger.end_floor == 0:
                    self.assign_lift(passenger)
        else:
            # Daytime and night
            for passenger in self.passengers:
                if random.random() < 0.1:
                    self.assign_lift(passenger)

    def assign_lift(self, passenger):
        available_lifts = [lift for lift in self.lifts if not lift.is_busy]
        if available_lifts:
            closest_lift = min(available_lifts, key=lambda lift: abs(lift.current_floor - passenger.start_floor))
            closest_lift.add_passenger(passenger)
            print(f"Passenger from floor {passenger.start_floor} to {passenger.end_floor} assigned to lift {self.lifts.index(closest_lift)}")
        else:
            print(f"No available lift for passenger from floor {passenger.start_floor} to {passenger.end_floor}")

    def move_lifts(self):
        for lift in self.lifts:
            if lift.passengers:
                destination_floor = lift.passengers[0].end_floor
                lift.move_to_floor(destination_floor)
                lift.remove_passenger(lift.passengers[0])

