import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.direction = 'up'

    def move(self):
        if self.direction == 'up':
            self.current_floor = min(self.current_floor + 1, self.num_floors)
        else:
            self.current_floor = max(self.current_floor - 1, 0)

        if self.current_floor == 0:
            self.direction = 'up'
        elif self.current_floor == self.num_floors:
            self.direction = 'down'

        for passenger in self.passengers[:]:
            if passenger.destination == self.current_floor:
                self.passengers.remove(passenger)

        return self.current_floor

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

class Passenger:
    def __init__(self, start_floor, destination_floor):
        self.start_floor = start_floor
        self.destination_floor = destination_floor

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passengers = []

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

    def simulate_day(self, start_time, end_time):
        current_time = start_time
        while current_time < end_time:
            print(f"Time: {current_time}")
            for lift in self.lifts:
                current_floor = lift.move()
                print(f"Lift at floor {current_floor}")

            new_passengers = self.generate_passengers(current_time)
            self.passengers.extend(new_passengers)

            for passenger in self.passengers[:]:
                available_lifts = [lift for lift in self.lifts if lift.current_floor == passenger.start_floor]
                if available_lifts:
                    lift = random.choice(available_lifts)
                    lift.add_passenger(passenger)
                    self.passengers.remove(passenger)

            current_time += 1

    def generate_passengers(self, current_time):
        new_passengers = []
        if 8 <= current_time < 10:
            num_passengers = random.randint(10, 50)
        elif 17 <= current_time < 19:
            num_passengers = random.randint(10, 50)
        else:
            num_passengers = random.randint(1, 10)

        for _ in range(num_passengers):
            start_floor = random.randint(0, self.num_floors - 1)
            destination_floor = random.randint(0, self.num_floors - 1)
            while destination_floor == start_floor:
                destination_floor = random.randint(0, self.num_floors - 1)
            new_passengers.append(Passenger(start_floor, destination_floor))

        return new_passengers

