import time

class Lift:
    def __init__(self, building_floors):
        self.current_floor = 0
        self.building_floors = building_floors
        self.passengers = []

    def move_to_floor(self, floor):
        print(f"Lift moving from floor {self.current_floor} to floor {floor}")
        self.current_floor = floor

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

    def remove_passenger(self, passenger):
        self.passengers.remove(passenger)

    def is_empty(self):
        return len(self.passengers) == 0

class Passenger:
    def __init__(self, start_floor, end_floor):
        self.start_floor = start_floor
        self.end_floor = end_floor

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passengers = []

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

    def simulate_day(self, start_time, end_time):
        current_time = start_time
        while current_time < end_time:
            self.handle_morning_rush(current_time)
            self.handle_day_traffic(current_time)
            self.handle_evening_rush(current_time)
            self.handle_night_traffic(current_time)
            current_time += 1

    def handle_morning_rush(self, current_time):
        if 8 <= current_time < 10:
            for _ in range(random.randint(10, 20)):
                start_floor = random.randint(1, self.num_floors - 1)
                end_floor = 0
                passenger = Passenger(start_floor, end_floor)
                self.add_passenger(passenger)

    def handle_day_traffic(self, current_time):
        if 10 <= current_time < 16:
            for _ in range(random.randint(5, 10)):
                start_floor = random.randint(1, self.num_floors - 1)
                end_floor = random.randint(1, self.num_floors - 1)
                while end_floor == start_floor:
                    end_floor = random.randint(1, self.num_floors - 1)
                passenger = Passenger(start_floor, end_floor)
                self.add_passenger(passenger)

    def handle_evening_rush(self, current_time):
        if 16 <= current_time < 18:
            for _ in range(random.randint(10, 20)):
                start_floor = 0
                end_floor = random.randint(1, self.num_floors - 1)
                passenger = Passenger(start_floor, end_floor)
                self.add_passenger(passenger)

    def handle_night_traffic(self, current_time):
        if 18 <= current_time or current_time < 8:
            for _ in range(random.randint(1, 5)):
                start_floor = random.randint(1, self.num_floors - 1)
                end_floor = random.randint(1, self.num_floors - 1)
                while end_floor == start_floor:
                    end_floor = random.randint(1, self.num_floors - 1)
                passenger = Passenger(start_floor, end_floor)
                self.add_passenger(passenger)

    def run_lifts(self):
        while self.passengers:
            for lift in self.lifts:
                if lift.is_empty() and self.passengers:
                    passenger = self.passengers.pop(0)
                    lift.add_passenger(passenger)
                    lift.move_to_floor(passenger.end_floor)
                    lift.remove_passenger(passenger)
                elif lift.passengers:
                    next_floor = min(p.end_floor for p in lift.passengers)
                    lift.move_to_floor(next_floor)
                    for passenger in lift.passengers:
                        if passenger.end_floor == next_floor:
                            lift.remove_passenger(passenger)
            time.sleep(1)

