import random
import time

class Lift:
    def __init__(self, building_floors):
        self.current_floor = 0
        self.building_floors = building_floors
        self.passengers = []
        self.direction = "up"
        self.busy = False

    def move(self):
        if self.direction == "up":
            self.current_floor += 1
            if self.current_floor == self.building_floors:
                self.direction = "down"
        else:
            self.current_floor -= 1
            if self.current_floor == 0:
                self.direction = "up"
        self.busy = True
        time.sleep(1)
        self.busy = False

    def pick_up(self, passenger):
        self.passengers.append(passenger)

    def drop_off(self, passenger):
        self.passengers.remove(passenger)

