    def run_simulation(self, simulation_time):
        while simulation_time > 0:
            for lift in self.lifts:
                if lift.passengers:
                    for passenger in lift.passengers:
                        if passenger.end_floor == lift.current_floor:
                            lift.drop_off(passenger)
                            print(f"Passenger from floor {passenger.start_floor} to {passenger.end_floor} has been dropped off.")
                if not lift.busy:
                    lift.move()
            for _ in range(random.randint(0, 5)):
