            self.move_to_floor(next_request[0])

    def load_unload_passengers(self):
        for i in range(len(self.passengers) - 1, -1, -1):
            if self.passengers[i].destination == self.current_floor:
                self.passengers.pop(i)
        if self.current_floor in self.building.passengers_waiting:
