passenger_queues = [[] for _ in range(NUM_FLOORS)]
current_floor = [0] * NUM_LIFTS
destination_floor = [0] * NUM_LIFTS

def simulate_lift_operation():
    while True:
        # Check for new passengers
        for floor in range(NUM_FLOORS):
            if random.random() < get_passenger_arrival_rate(floor):
                passenger_queues[floor].append(floor)

        # Assign lifts to passengers
        for lift_id in range(NUM_LIFTS):
            if lift_status[lift_id] == 0 and passenger_queues:
                # Find the nearest floor with passengers
                nearest_floor = min(passenger_queues, key=lambda x: abs(x - current_floor[lift_id]))
                destination_floor[lift_id] = nearest_floor
                lift_status[lift_id] = 1
                passenger_queues[nearest_floor].pop(0)

        # Move lifts
        for lift_id in range(NUM_LIFTS):
            if lift_status[lift_id] == 1:
                if current_floor[lift_id] < destination_floor[lift_id]:
                    current_floor[lift_id] += 1
                elif current_floor[lift_id] > destination_floor[lift_id]:
                    current_floor[lift_id] -= 1
                else:
                    lift_status[lift_id] = 2

        # Unload passengers
        for lift_id in range(NUM_LIFTS):
            if lift_status[lift_id] == 2:
                if current_floor[lift_id] == destination_floor[lift_id]:
                    lift_status[lift_id] = 0

