            self.current_floor += 1
            if self.current_floor == self.target_floor:
                self.state = LiftState.STOPPED
                self.unload_passengers()
        elif self.state == LiftState.MOVING_DOWN:
            self.current_floor -= 1
            if self.current_floor == self.target_floor:
                self.state = LiftState.STOPPED
                self.unload_passengers()
        elif self.state == LiftState.STOPPED:
            if len(self.passengers) > 0:
                self.state = LiftState.MOVING_UP if self.passengers[0].target_floor > self.current_floor else LiftState.MOVING_DOWN
                self.target_floor = self.passengers[0].target_floor
            else:
                self.state = LiftState.IDLE

