    def handle_requests(self, current_time):
        for floor in range(self.num_floors):
            if random.random() < self.get_request_probability(current_time, floor):
                self.floor_requests[floor] += 1
                self.assign_lift(floor)

    def assign_lift(self, floor):
        min_distance = float('inf')
        closest_lift = None
        for i, lift in enumerate(self.lifts):
            distance = abs(lift - floor)
            if distance < min_distance:
                min_distance = distance
                closest_lift = i
        self.lifts[closest_lift] = floor

    def move_lifts(self):
        for i, lift in enumerate(self.lifts):
            if lift < self.num_floors - 1:
                self.lifts[i] += 1

    def get_request_probability(self, current_time, floor):
        if current_time < 8 or current_time >= 20:
