        # Morning and evening rush hours
        if 8 <= time.localtime().tm_hour < 10 or 17 <= time.localtime().tm_hour < 19:
            for _ in range(num_people // 10):
                start_floor = random.randint(0, num_floors - 1)
                end_floor = random.randint(0, num_floors - 1)
                floor_traffic[start_floor] += 1
                floor_traffic[end_floor] += 1
        # Daytime traffic
        elif 10 <= time.localtime().tm_hour < 17:
            for _ in range(num_people // 20):
                start_floor = random.randint(0, num_floors - 1)
                end_floor = random.randint(0, num_floors - 1)
                floor_traffic[start_floor] += 1
                floor_traffic[end_floor] += 1
        # Night-time
        else:
            for _ in range(num_people // 50):
                start_floor = random.randint(0, num_floors - 1)
                end_floor = random.randint(0, num_floors - 1)
                floor_traffic[start_floor] += 1
                floor_traffic[end_floor] += 1

        # Move the lifts
        for lift in lift_states:
            if lift['passengers']:
                current_floor = lift['location']
                for passenger in lift['passengers'][:]:
                    if passenger == current_floor:
                        lift['passengers'].remove(passenger)
                        floor_traffic[passenger] -= 1
                    else:
                        if passenger > current_floor:
                            lift['location'] += 1
                        else:
                            lift['location'] -= 1
            else:
                busy_floors = [i for i, count in enumerate(floor_traffic) if count > 0]
                if busy_floors:
                    target_floor = random.choice(busy_floors)
                    if target_floor > lift['location']:
                        lift['location'] += 1
                    elif target_floor < lift['location']:
                        lift['location'] -= 1

        # Load passengers into the lifts
        for i, count in enumerate(floor_traffic):
            if count > 0:
                available_lifts = [lift for lift in lift_states if lift['location'] == i and len(lift['passengers']) < num_people // num_lifts]
                if available_lifts:
                    lift = random.choice(available_lifts)
                    lift['passengers'].append(i)
                    floor_traffic[i] -= 1

        time.sleep(0.1)

skyscraper_lift_simulation(50, 10, 500)

import random
import time

def simulate_lift_runs(num_floors, num_lifts, num_people):
    occupancy_levels = [0] * num_floors
    peak_hours = [(7, 10), (17, 20)]

    while True:
        for hour in range(24):
            for minute in range(60):
                for lift in range(num_lifts):
                    if random.randint(1, 100) <= 80:
                        current_floor = random.randint(0, num_floors-1)
                        target_floor = random.randint(0, num_floors-1)
                        num_passengers = random.randint(1, num_people)
                        occupancy_levels[current_floor] -= num_passengers
                        occupancy_levels[target_floor] += num_passengers
                        print(f"Lift {lift} moved from floor {current_floor} to floor {target_floor} with {num_passengers} passengers.")

                is_peak_hour = False
                for start, end in peak_hours:
                    if start <= hour < end:
                        is_peak_hour = True
                        break

                if is_peak_hour:
                    for floor in range(num_floors):
                        num_passengers = random.randint(1, num_people)
                        occupancy_levels[floor] += num_passengers
                        print(f"New passengers arrived at floor {floor}: {num_passengers}")
                else:
                    for floor in range(num_floors):
                        num_passengers = random.randint(1, num_people // 2)
                        occupancy_levels[floor] += num_passengers
                        print(f"New passengers arrived at floor {floor}: {num_passengers}")

                time.sleep(1)

simulate_lift_runs(20, 4, 10)
